let currentLang = 'zh';

function t(key, ...args) {
  const val = I18N[currentLang][key] || I18N['zh'][key] || key;
  return typeof val === 'function' ? val(...args) : val;
}

function applyI18n() {
  document.title = t('siteTitle');
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    el.textContent = t(key);
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPlaceholder);
  });
  const langBtn = document.getElementById('langToggle');
  if (langBtn) langBtn.textContent = currentLang === 'zh' ? 'EN' : '中文';
  // re-render cards if any
  const grid = document.getElementById('cardGrid');
  if (grid && grid.__renderFn) grid.__renderFn();
}

// ── data loading ──────────────────────────────────────────────────────────
async function loadIndex() {
  // 优先读取 refresh_index.js 内嵌的数据（双击 file:// 时 fetch 会被阻止）
  if (window.__CARDS_INDEX__) return window.__CARDS_INDEX__;
  try {
    const response = await fetch('./cards-index.json', { cache: 'no-store' });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    return await response.json();
  } catch (error) {
    console.error(error);
    document.getElementById('resultSummary').textContent = '未找到卡片数据，请先运行 refresh_index.js 刷新索引再重新打开此页。';
    return { generatedAt: null, total: 0, cards: [] };
  }
}

function formatDateTime(value) {
  if (!value) return '--';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString('zh-CN', { hour12: false });
}

function initials(title) {
  const parts = String(title || 'G').split(/[^A-Za-z0-9\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]+/).filter(Boolean);
  return (parts.slice(0, 2).map(part => part[0]).join('') || 'G').toUpperCase();
}

function matchesSearch(card, term) {
  if (!term) return true;
  const target = [card.title, card.fileName, ...(card.tags || [])].join(' ').toLowerCase();
  return target.includes(term.toLowerCase());
}

function parseNumeric(str) {
  if (str == null) return -Infinity;
  const cleaned = String(str).replace(/[^\d.]/g, '');
  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : -Infinity;
}

function sortCards(cards, mode) {
  const list = [...cards];
  switch (mode) {
    case 'updated-asc':
      return list.sort((a, b) => new Date(a.updatedAt) - new Date(b.updatedAt));
    case 'title-asc':
      return list.sort((a, b) => a.title.localeCompare(b.title, 'zh-CN'));
    case 'title-desc':
      return list.sort((a, b) => b.title.localeCompare(a.title, 'zh-CN'));
    case 'downloads-desc':
      return list.sort((a, b) => parseNumeric(b.totalDownloads) - parseNumeric(a.totalDownloads));
    case 'downloads-asc':
      return list.sort((a, b) => parseNumeric(a.totalDownloads) - parseNumeric(b.totalDownloads));
    case 'revenue-desc':
      return list.sort((a, b) => parseNumeric(b.totalRevenue) - parseNumeric(a.totalRevenue));
    case 'revenue-asc':
      return list.sort((a, b) => parseNumeric(a.totalRevenue) - parseNumeric(b.totalRevenue));
    case 'updated-desc':
    default:
      return list.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
  }
}

function renderCards(cards) {
  const grid = document.getElementById('cardGrid');
  const empty = document.getElementById('emptyState');
  grid.innerHTML = '';

  empty.querySelector('h2') && (empty.querySelector('h2').textContent = t('noMatch'));
  empty.querySelector('p') && (empty.querySelector('p').textContent = t('noMatchHint'));

  if (!cards.length) {
    empty.classList.remove('hidden');
    return;
  }
  empty.classList.add('hidden');

  cards.forEach(card => {
    const article = document.createElement('article');
    article.className = 'library-card';
    const iconHtml = card.iconUrl
      ? `<img class="card-icon" src="${card.iconUrl}" alt="${card.title} icon" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
        + `<div class="card-badge" style="display:none">${initials(card.title)}</div>`
      : `<div class="card-badge">${initials(card.title)}</div>`;
    const statsHtml = (card.totalDownloads || card.totalRevenue) ? `
      <div class="card-stats">
        ${card.totalDownloads ? `<div class="stat-chip"><span class="stat-chip-label" data-i18n="labelTotalDl">${t('labelTotalDl')}</span><span class="stat-chip-val">${card.totalDownloads}</span></div>` : ''}
        ${card.totalRevenue ? `<div class="stat-chip"><span class="stat-chip-label" data-i18n="labelTotalRev">${t('labelTotalRev')}</span><span class="stat-chip-val">${card.totalRevenue}</span></div>` : ''}
      </div>` : '';
    article.innerHTML = `
      <div class="card-top">
        <div class="card-icon-wrap">${iconHtml}</div>
        <div class="card-title-group">
          <h2 class="card-title">${card.title}</h2>
          <span class="card-genre">${card.sourceType}</span>
        </div>
      </div>
      ${statsHtml}
      <div class="meta-list">
        <div class="meta-item"><span data-i18n="labelUpdated">${t('labelUpdated')}</span>：${formatDateTime(card.updatedAt)}</div>
      </div>
      <div class="tags">${(card.tags || []).filter(tag => tag !== '竞品分析卡片').map(tag => `<span class="tag">${tag}</span>`).join('')}</div>
      <div class="card-actions">
        <a class="open-btn" href="${card.relativePath}" target="_blank" rel="noopener noreferrer" data-i18n="openCard">${t('openCard')}</a>
      </div>
    `;
    grid.appendChild(article);
  });
}

function attachEvents(allCards) {
  const searchInput = document.getElementById('searchInput');
  const sortSelect = document.getElementById('sortSelect');
  const filterSelect = document.getElementById('filterSelect');
  const summary = document.getElementById('resultSummary');

  // 动态填充类型筛选选项
  const genres = [...new Set(allCards.map(c => c.sourceType).filter(Boolean))].sort();
  filterSelect.innerHTML = `<option value="all">${t('allCards')}</option>`
    + genres.map(g => `<option value="${g}">${g}</option>`).join('');

  function update() {
    const term = searchInput.value.trim();
    const filter = filterSelect.value;
    const filtered = allCards.filter(card => (filter === 'all' || card.sourceType === filter) && matchesSearch(card, term));
    const sorted = sortCards(filtered, sortSelect.value);
    summary.textContent = t('showing', sorted.length, allCards.length);
    renderCards(sorted);
  }

  // store for re-render on lang switch
  document.getElementById('cardGrid').__renderFn = update;

  searchInput.addEventListener('input', update);
  sortSelect.addEventListener('change', update);
  filterSelect.addEventListener('change', update);
  update();
}

function attachDialog() {
  const btn = document.getElementById('refreshHintBtn');
  const dialog = document.getElementById('refreshDialog');
  btn.addEventListener('click', () => dialog.showModal());
}

function attachLangToggle() {
  const btn = document.getElementById('langToggle');
  if (!btn) return;
  btn.addEventListener('click', () => {
    currentLang = currentLang === 'zh' ? 'en' : 'zh';
    applyI18n();
    // re-render filter options with new lang
    const filterSelect = document.getElementById('filterSelect');
    if (filterSelect) {
      const current = filterSelect.value;
      filterSelect.options[0].textContent = t('allCards');
      filterSelect.value = current;
    }
  });
}

(async function init() {
  const data = await loadIndex();
  document.getElementById('cardCount').textContent = data.total ?? 0;
  document.getElementById('generatedAt').textContent = formatDateTime(data.generatedAt);
  attachEvents(data.cards || []);
  attachDialog();
  attachLangToggle();
  applyI18n();
})();
